1	// Smoke test for the deployed apify-webhook edge function (US-016, US-017).
2	//
3	// Usage: bun run scripts/test/apify-webhook.ts
4	// Requires SUPABASE_URL, SUPABASE_ANON_KEY, APIFY_WEBHOOK_SECRET in .env.
5	//
6	// Covers the paths that don't need a live Apify run — the SUCCEEDED branch
7	// (which pulls a real dataset) is exercised end-to-end in the iteration's
8	// MCP verification, not here.
9	//
10	// Asserts:
11	//   1. Missing X-Apify-Webhook-Secret → 401 UNAUTHORIZED
12	//   2. Wrong secret → 401 UNAUTHORIZED (constant-time reject)
13	//   3. Malformed JSON body with valid secret → 400 INVALID_JSON
14	//   4. Missing required fields → 400 INVALID_REQUEST
15	//   5. scrape_mode='ig_posts' → 200 { skipped:'unsupported_scrape_mode' }
16	//      (ig_posts ships in US-018; tiktok_profile+ig_details are live now)
17	//   6. tiktok_profile + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
18	//   7. Replay same tiktok_profile run_id → 200 { inserted:false, duplicate:true }
19	//   8. ig_details + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
20	//   9. Replay same ig_details run_id → 200 { inserted:false, duplicate:true }
21	
22	const supabaseUrl = process.env.SUPABASE_URL;
23	const anonKey = process.env.SUPABASE_ANON_KEY;
24	const webhookSecret = process.env.APIFY_WEBHOOK_SECRET;
25	if (!supabaseUrl || !anonKey || !webhookSecret) {
26	  console.error(
27	    "SUPABASE_URL, SUPABASE_ANON_KEY, and APIFY_WEBHOOK_SECRET are required in .env",
28	  );
29	  process.exit(1);
30	}
31	
32	const endpoint = `${supabaseUrl}/functions/v1/apify-webhook`;
33	// anon key is required by the Supabase gateway even for verify_jwt=false
34	// functions; the edge function itself validates X-Apify-Webhook-Secret.
35	const gatewayHeaders = {
36	  Authorization: `Bearer ${anonKey}`,
37	  apikey: anonKey,
38	};
39	
40	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
41	const SEED_INSTAGRAM_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111021";
42	const unique = Date.now();
43	
44	function basePayload(overrides: Record<string, unknown> = {}) {
45	  const runId = `us017_test_${unique}_${Math.random().toString(36).slice(2, 10)}`;
46	  return {
47	    eventType: "ACTOR.RUN.FAILED",
48	    resource: {
49	      id: runId,
50	      defaultDatasetId: `dataset_${runId}`,
51	      status: "FAILED",
52	      actId: "clockworks~tiktok-scraper",
53	    },
54	    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
55	    scrape_mode: "tiktok_profile",
56	    run_id: runId,
57	    apify_finished_at: new Date().toISOString(),
58	    ...overrides,
59	  };
60	}
61	
62	async function postRaw(
63	  body: string | object,
64	  extraHeaders: Record<string, string> = {},
65	) {
66	  const res = await fetch(endpoint, {
67	    method: "POST",
68	    headers: {
69	      "Content-Type": "application/json",
70	      ...gatewayHeaders,
71	      ...extraHeaders,
72	    },
73	    body: typeof body === "string" ? body : JSON.stringify(body),
74	  });
75	  const data = await res.json().catch(() => null);
76	  return { status: res.status, data };
77	}
78	
79	function expect(label: string, cond: boolean, ctx: unknown) {
80	  if (!cond) {
81	    console.error(`FAIL ${label}:`, ctx);
82	    process.exit(1);
83	  }
84	  console.log(`ok — ${label}`);
85	}
86	
87	// 1. Missing secret header
88	{
89	  const r = await postRaw(basePayload());
90	  expect(
91	    "missing secret → 401 UNAUTHORIZED",
92	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
93	    r,
94	  );
95	}
96	
97	// 2. Wrong secret header
98	{
99	  const r = await postRaw(basePayload(), {
100	    "X-Apify-Webhook-Secret": "definitely-not-the-real-secret",
101	  });
102	  expect(
103	    "wrong secret → 401 UNAUTHORIZED",
104	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
105	    r,
106	  );
107	}
108	
109	// 3. Malformed JSON (valid secret)
110	{
111	  const r = await postRaw("{not json", {
112	    "X-Apify-Webhook-Secret": webhookSecret,
113	  });
114	  expect(
115	    "malformed json → 400 INVALID_JSON",
116	    r.status === 400 && r.data?.error === "INVALID_JSON",
117	    r,
118	  );
119	}
120	
121	// 4. Missing required fields
122	{
123	  const r = await postRaw(
124	    { eventType: "ACTOR.RUN.SUCCEEDED" },
125	    { "X-Apify-Webhook-Secret": webhookSecret },
126	  );
127	  expect(
128	    "missing fields → 400 INVALID_REQUEST",
129	    r.status === 400 && r.data?.error === "INVALID_REQUEST",
130	    r,
131	  );
132	}
133	
134	// 5. ig_posts scrape_mode → unsupported_scrape_mode (ig_posts ships US-018)
135	{
136	  const r = await postRaw(
137	    basePayload({ scrape_mode: "ig_posts" }),
138	    { "X-Apify-Webhook-Secret": webhookSecret },
139	  );
140	  expect(
141	    "ig_posts → 200 skipped",
142	    r.status === 200 && r.data?.skipped === "unsupported_scrape_mode",
143	    r,
144	  );
145	}
146	
147	// 6. tiktok_profile + FAILED event → inserts failed snapshot
148	const failedTikTokRunBody = basePayload();
149	{
150	  const r = await postRaw(failedTikTokRunBody, {
151	    "X-Apify-Webhook-Secret": webhookSecret,
152	  });
153	  expect(
154	    "tiktok_profile FAILED → 200 inserted",
155	    r.status === 200 && r.data?.inserted === true && r.data?.duplicate === false,
156	    r,
157	  );
158	}
159	
160	// 7. Same tiktok_profile run_id replay → idempotent duplicate
161	{
162	  const r = await postRaw(failedTikTokRunBody, {
163	    "X-Apify-Webhook-Secret": webhookSecret,
164	  });
165	  expect(
166	    "replay same tiktok_profile run_id → 200 duplicate",
167	    r.status === 200 && r.data?.inserted === false && r.data?.duplicate === true,
168	    r,
169	  );
170	}
171	
172	// 8. ig_details + FAILED event → inserts failed snapshot against the IG seed link
173	const failedIgDetailsRunBody = basePayload({
174	  scrape_mode: "ig_details",
175	  social_link_id: SEED_INSTAGRAM_SOCIAL_LINK_ID,
176	  resource: {
177	    id: `us017_ig_${unique}_${Math.random().toString(36).slice(2, 10)}`,
178	    defaultDatasetId: `dataset_ig_${unique}`,
179	    status: "FAILED",
180	    actId: "apify~instagram-scraper",
181	  },
182	  run_id: `us017_ig_${unique}_${Math.random().toString(36).slice(2, 10)}`,
183	});
184	{
185	  const r = await postRaw(failedIgDetailsRunBody, {
186	    "X-Apify-Webhook-Secret": webhookSecret,
187	  });
188	  expect(
189	    "ig_details FAILED → 200 inserted",
190	    r.status === 200 && r.data?.inserted === true && r.data?.duplicate === false,
191	    r,
192	  );
193	}
194	
195	// 9. Same ig_details run_id replay → idempotent duplicate
196	{
197	  const r = await postRaw(failedIgDetailsRunBody, {
198	    "X-Apify-Webhook-Secret": webhookSecret,
199	  });
200	  expect(
201	    "replay same ig_details run_id → 200 duplicate",
202	    r.status === 200 && r.data?.inserted === false && r.data?.duplicate === true,
203	    r,
